import json
import re
from dataclasses import dataclass
from pathlib import Path
from typing import Dict, List, Optional, Tuple

import torch
from peft import PeftModel
from transformers import AutoProcessor, Qwen2_5_VLForConditionalGeneration

DEFAULT_MIN_PIXELS = 256 * 28 * 28
DEFAULT_MAX_PIXELS = 512 * 28 * 28
GRID_SIZE = 1000.0


@dataclass
class ParsedPrediction:
    kind: str
    values: List[float]
    raw_text: str = ""


def _has_weights(path: Path) -> bool:
    if not path.exists() or not path.is_dir():
        return False
    required_any = [
        "config.json",
        "model.safetensors",
        "model.safetensors.index.json",
        "pytorch_model.bin",
        "pytorch_model.bin.index.json",
        "model-00001-of-00002.safetensors",
    ]
    return any((path / name).exists() for name in required_any)


def _read_meta(ckpt_dir: Path) -> Dict:
    meta_path = ckpt_dir / "meta.json"
    if not meta_path.exists():
        return {}
    try:
        return json.loads(meta_path.read_text())
    except Exception:
        return {}


def resolve_base_model_dir(checkpoint: str) -> str:
    ckpt_path = Path(checkpoint).resolve()
    ckpt_dir = ckpt_path if ckpt_path.is_dir() else ckpt_path.parent
    cwd = Path.cwd().resolve()
    meta = _read_meta(ckpt_dir)

    candidates = [
        ckpt_dir / "base_model",
        ckpt_dir.parent / "base_model",
        ckpt_dir.parent / "baseline" / "base_model",
        ckpt_dir.parent.parent / "baseline" / "base_model",
        cwd / "checkpoints" / ckpt_dir.name / "base_model",
        cwd / "checkpoints" / "baseline" / "base_model",
        cwd / "baseline" / "base_model",
        Path("/workspace/checkpoints") / ckpt_dir.name / "base_model",
        Path("/workspace/checkpoints/baseline/base_model"),
        Path("/workspace/baseline/base_model"),
    ]
    for key in ["base_model_dir", "base_model", "base_dir"]:
        value = meta.get(key)
        if value:
            p = Path(value)
            candidates.append(p if p.is_absolute() else (ckpt_dir / p).resolve())
            candidates.append(p if p.is_absolute() else (cwd / p).resolve())

    seen = set()
    ordered = []
    for p in candidates:
        s = str(p)
        if s not in seen:
            seen.add(s)
            ordered.append(p)

    for p in ordered:
        if _has_weights(p):
            return str(p)
    raise FileNotFoundError(f"Could not find packaged base model for checkpoint {checkpoint}")


def load_processor(checkpoint: str, min_pixels: int = DEFAULT_MIN_PIXELS, max_pixels: int = DEFAULT_MAX_PIXELS):
    ckpt_dir = Path(checkpoint).resolve()
    base_dir = Path(resolve_base_model_dir(checkpoint))
    candidates = []
    if (ckpt_dir / "processor").exists():
        candidates.append(ckpt_dir / "processor")
    candidates.append(ckpt_dir)
    if (base_dir / "processor").exists():
        candidates.append(base_dir / "processor")
    candidates.append(base_dir)

    last_err = None
    for cand in candidates:
        try:
            return AutoProcessor.from_pretrained(
                str(cand),
                local_files_only=True,
                trust_remote_code=False,
                min_pixels=min_pixels,
                max_pixels=max_pixels,
            )
        except Exception as e:
            last_err = e
    raise last_err


def load_model_for_inference(checkpoint: str, min_pixels: int = DEFAULT_MIN_PIXELS, max_pixels: int = DEFAULT_MAX_PIXELS):
    base_dir = resolve_base_model_dir(checkpoint)
    processor = load_processor(checkpoint, min_pixels=min_pixels, max_pixels=max_pixels)
    model = Qwen2_5_VLForConditionalGeneration.from_pretrained(
        base_dir,
        torch_dtype=torch.bfloat16,
        local_files_only=True,
        trust_remote_code=False,
        device_map="auto",
    )
    ckpt_dir = Path(checkpoint).resolve()
    if (ckpt_dir / "adapter_config.json").exists():
        model = PeftModel.from_pretrained(model, str(ckpt_dir), local_files_only=True)
    model.eval()
    return model, processor


def build_messages(instruction: str):
    prompt = (
        "Locate the UI element described by the instruction. "
        "Return only coordinates on a 0-1000 grid. "
        "Preferred format: <point>x y</point>. "
        "You may also answer <box>x1 y1 x2 y2</box>. "
        "No explanation.\n"
        f"Instruction: {instruction}"
    )
    return [
        {
            "role": "user",
            "content": [
                {"type": "image"},
                {"type": "text", "text": prompt},
            ],
        }
    ]


def _extract_numbers(text: str) -> List[float]:
    return [float(x) for x in re.findall(r"-?\d+(?:\.\d+)?", text)]


def parse_prediction_text(raw_text: str) -> Optional[ParsedPrediction]:
    if raw_text is None:
        return None
    text = raw_text.strip()
    if not text:
        return None

    patterns_box = [
        r"<box>\s*(-?\d+(?:\.\d+)?)\s+(-?\d+(?:\.\d+)?)\s+(-?\d+(?:\.\d+)?)\s+(-?\d+(?:\.\d+)?)\s*</box>",
        r"<bbox>\s*\(?\s*(-?\d+(?:\.\d+)?)\s*,\s*(-?\d+(?:\.\d+)?)\s*\)?\s*,?\s*\(?\s*(-?\d+(?:\.\d+)?)\s*,\s*(-?\d+(?:\.\d+)?)\s*\)?\s*</bbox>",
        r"\(\s*(-?\d+(?:\.\d+)?)\s*,\s*(-?\d+(?:\.\d+)?)\s*,\s*(-?\d+(?:\.\d+)?)\s*,\s*(-?\d+(?:\.\d+)?)\s*\)",
    ]
    for pat in patterns_box:
        m = re.search(pat, text, flags=re.IGNORECASE | re.DOTALL)
        if m:
            vals = [float(m.group(i)) for i in range(1, 5)]
            return ParsedPrediction(kind="bbox", values=vals, raw_text=raw_text)

    patterns_point = [
        r"<point>\s*(-?\d+(?:\.\d+)?)\s+(-?\d+(?:\.\d+)?)\s*</point>",
        r"point\s*[:=]\s*\(?\s*(-?\d+(?:\.\d+)?)\s*,\s*(-?\d+(?:\.\d+)?)\s*\)?",
        r"\(\s*(-?\d+(?:\.\d+)?)\s*,\s*(-?\d+(?:\.\d+)?)\s*\)",
    ]
    for pat in patterns_point:
        m = re.search(pat, text, flags=re.IGNORECASE | re.DOTALL)
        if m:
            vals = [float(m.group(1)), float(m.group(2))]
            return ParsedPrediction(kind="point", values=vals, raw_text=raw_text)

    nums = _extract_numbers(text)
    if len(nums) >= 4:
        return ParsedPrediction(kind="bbox", values=nums[:4], raw_text=raw_text)
    if len(nums) >= 2:
        return ParsedPrediction(kind="point", values=nums[:2], raw_text=raw_text)
    return None


def parse_prediction(raw_text: str) -> Optional[ParsedPrediction]:
    return parse_prediction_text(raw_text)


def _clip(v: float, lo: float, hi: float) -> float:
    return max(lo, min(hi, v))


def _grid_to_abs_xy(x: float, y: float, image_width: float, image_height: float) -> Tuple[float, float]:
    x = x / GRID_SIZE * image_width
    y = y / GRID_SIZE * image_height
    return _clip(x, 0.0, image_width), _clip(y, 0.0, image_height)


def _grid_to_abs_bbox(vals: List[float], image_width: float, image_height: float) -> List[float]:
    x1, y1 = _grid_to_abs_xy(vals[0], vals[1], image_width, image_height)
    x2, y2 = _grid_to_abs_xy(vals[2], vals[3], image_width, image_height)
    xa, xb = sorted([x1, x2])
    ya, yb = sorted([y1, y2])
    return [xa, ya, xb, yb]


def generate_raw(model, processor, image, instruction: str, max_new_tokens: int = 24) -> str:
    messages = build_messages(instruction)
    text = processor.apply_chat_template(messages, tokenize=False, add_generation_prompt=True)
    inputs = processor(
        text=[text],
        images=[image],
        return_tensors="pt",
        padding=True,
    )
    inputs = {k: v.to(model.device) if hasattr(v, "to") else v for k, v in inputs.items()}
    with torch.no_grad():
        generated = model.generate(
            **inputs,
            max_new_tokens=max_new_tokens,
            do_sample=False,
            use_cache=True,
        )
    prompt_len = inputs["input_ids"].shape[1]
    new_ids = generated[:, prompt_len:]
    text_out = processor.batch_decode(new_ids, skip_special_tokens=True, clean_up_tokenization_spaces=False)[0]
    return text_out.strip()


def generate_prediction(model, processor, image, instruction: str, image_width: float, image_height: float):
    raw = generate_raw(model, processor, image, instruction)
    parsed = parse_prediction_text(raw)
    if parsed is None:
        return {"point": [float(image_width) / 2.0, float(image_height) / 2.0], "raw": raw}
    if parsed.kind == "bbox" and len(parsed.values) >= 4:
        bbox = _grid_to_abs_bbox(parsed.values[:4], image_width, image_height)
        if bbox[2] <= bbox[0] or bbox[3] <= bbox[1]:
            cx = (bbox[0] + bbox[2]) / 2.0
            cy = (bbox[1] + bbox[3]) / 2.0
            return {"point": [_clip(cx, 0.0, image_width), _clip(cy, 0.0, image_height)], "raw": raw}
        return {"bbox": bbox, "raw": raw}
    if parsed.kind == "point" and len(parsed.values) >= 2:
        x, y = _grid_to_abs_xy(parsed.values[0], parsed.values[1], image_width, image_height)
        return {"point": [x, y], "raw": raw}
    return {"point": [float(image_width) / 2.0, float(image_height) / 2.0], "raw": raw}
